try {
    const sessions =
        await this.sessionRepository.findActiveByDeviceOwnership(
            userId,
            existDeviceOwnership.id
        );

    const [removed] = await Promise.all([
        this.deviceOwnershipRepository.remove(
            userId,
            existDeviceOwnership.id,
            requestLog,
            removedBy
        ),
        this.sessionUtil.deleteAllLogins(userId, sessions),
    ]);

    return {
        metadataActivityLog:
            this.deviceUtil.mapActivityLogMetadata(removed),
    };
} catch (err: unknown) {
    throw new InternalServerErrorException({
        statusCode: EnumAppStatusCodeError.unknown,
        message: 'http.serverError.internalServerError',
        _error: err,
    });
}

if (lastVerification) {
    const today = this.helperService.dateCreate();
    const canResendAt = this.helperService.dateForward(
        lastVerification.createdAt,
        Duration.fromObject({
            minutes: this.userUtil.verificationExpiredInMinutes,
        })
    );

    if (today < canResendAt) {
        throw new BadRequestException({
            statusCode:
                EnumUserStatusCodeError.verificationEmailResendLimitExceeded,
            message: 'user.error.verificationEmailResendLimitExceeded',
            messageProperties: {
                resendIn: this.helperService.dateDiff(
                    today,
                    canResendAt
                ).minutes,
            },
        });
    }
}

try {
    const resetPassword = this.userUtil.forgotPasswordCreate(user.id);

    await this.userRepository.forgotPassword(
        user.id,
        email,
        resetPassword,
        requestLog
    );

    await this.notificationUtil.sendForgotPassword(user.id, {
        expiredAt: this.helperService.dateFormatToIso(
            resetPassword.expiredAt
        ),
        link: resetPassword.encryptedLink,
        reference: resetPassword.reference,
        expiredInMinutes: resetPassword.expiredInMinutes,
        resendInMinutes: resetPassword.resendInMinutes,
    });

    return;
} catch (err: unknown) {
    throw new InternalServerErrorException({
        statusCode: EnumAppStatusCodeError.unknown,
        message: 'http.serverError.internalServerError',
        _error: err,
    });
}

export type InferPayloadMap<
  TopicConfigurations extends readonly PubsubTopicConfiguration[],
> = {
  [Name in TopicConfigurations[number]['name']]: Extract<
    TopicConfigurations[number],
    { name: Name }
  > extends {
    schema?: infer InferredSchema;
  }
    ? InferredSchema extends PubsubSchemaConfiguration
      ? InferredSchema['type'] extends typeof SchemaTypes.Avro
        ? InferAvroPayload<InferredSchema['definition']>
        : InferredSchema['type'] extends typeof SchemaTypes.ProtocolBuffer
          ? InferredSchema['definition'] extends MessageType<
              infer InferredPayload
            >
            ? InferredPayload
            : never
          : Buffer
      : Buffer
    : Buffer;
};

for (const topicConfiguration of topicConfigurations) {
  if (topicNames.has(topicConfiguration.name)) {
    throw new PubsubConfigurationInvalidError(topicConfiguration.name, {
      key: 'name',
      reason: 'Duplicate topic name in configuration.',
      value: topicConfiguration.name,
    });
  }

  topicNames.add(topicConfiguration.name);

  for (const subscriptionConfiguration of topicConfiguration.subscriptions) {
    if (subscriptionNames.has(subscriptionConfiguration.name)) {
      throw new PubsubConfigurationInvalidError(topicConfiguration.name, {
        key: 'subscription.name',
        reason: 'Duplicate subscription name in configuration.',
        value: subscriptionConfiguration.name,
      });
    }

    subscriptionNames.add(subscriptionConfiguration.name);
  }
}

const taskList = fromPairs(
  handlers.map((h) => {
    const originalHandler = this.externalContextCreator.create(
      h.discoveredMethod.parentClass.instance,
      h.discoveredMethod.handler,
      h.discoveredMethod.methodName,
      undefined, // metadataKey
      undefined, // paramsFactory
      undefined, // contextId
      undefined, // inquirerId
      undefined, // options
      GRAPHILE_WORKER_CONTEXT_TYPE,
    );

    const taskHandlerName = h.meta.name as keyof GraphileWorkerTaskSchemas;
    const schema = this.options.tasksValidationSchemas[taskHandlerName];
    if (!schema) {
      throw new TaskHandlerValidationSchemaMissingError(h.meta.name);
    }

    return [
      taskHandlerName,
      createTaskGuard(taskHandlerName, schema, originalHandler),
    ];
  }),
);

const createDiscriminatorFactoryFrom = (parentFactory: ModelFactory) =>
    (discriminatorDefinition: TypegooseClass | TypegooseDiscriminator) => {
      if (isTypegooseClass(discriminatorDefinition)) {
        return buildProvider(discriminatorDefinition, (connection: Connection) =>
          getDiscriminatorModelForClass(
            parentFactory(connection),
            discriminatorDefinition
          )
        );
      }
      const { typegooseClass, discriminatorId } = discriminatorDefinition;
      return buildProvider(typegooseClass, (connection: Connection) =>
        getDiscriminatorModelForClass(
          parentFactory(connection),
          typegooseClass,
          discriminatorId
        )
      );
    };

if (isAdvancedSeparateProcessor(processor)) {
  const { path, ...processorOptions } = processor;
  return new workerClass(queueName, path, {
    connection: options.connection,
    sharedConnection: options.sharedConnection,
    prefix: options.prefix,
    ...processorOptions,
  });
} else if (isSeparateProcessor(processor)) {
  return new workerClass(queueName, processor, {
    connection: options.connection,
    sharedConnection: options.sharedConnection,
    prefix: options.prefix,
  });
} else if (isProcessorCallback(processor)) {
  return new workerClass(queueName, processor, {
    connection: options.connection,
    sharedConnection: options.sharedConnection,
    prefix: options.prefix,
  });
}

if (options.validator instanceof Function) {
  constraintCls = options.validator;
  const constraintClasses = getFromContainer(MetadataStorage).getTargetValidatorConstraints(options.validator);
  if (constraintClasses.length > 1) {
    throw `More than one implementation of ValidatorConstraintInterface found for validator on: ${options.target.name}:${options.propertyName}`;
  }
} else {
  const validator = options.validator;
  constraintCls = class CustomConstraint implements ValidatorConstraintInterface {
    validate(value: any, validationArguments?: ValidationArguments): Promise<boolean> | boolean {
      return validator.validate(value, validationArguments);
    }

    defaultMessage(validationArguments?: ValidationArguments): string {
      if (validator.defaultMessage) {
        return validator.defaultMessage(validationArguments);
      }

      return '';
    }
  };
  getMetadataStorage().addConstraintMetadata(new ConstraintMetadata(constraintCls, options.name, options.async));
}

switch (item.kind) {
  case 'SchemaDefinition':
    return this.toRootSchemaDefinitionStructure(item.operationTypes, mode);
  case 'ObjectTypeDefinition':
  case 'ObjectTypeExtension':
  case 'InputObjectTypeDefinition':
  case 'InputObjectTypeExtension':
    return this.toObjectTypeDefinitionStructure(item, mode, options);
  case 'InterfaceTypeDefinition':
  case 'InterfaceTypeExtension':
    return this.toObjectTypeDefinitionStructure(item, 'interface', options);
  case 'ScalarTypeDefinition':
  case 'ScalarTypeExtension':
    return this.toScalarDefinitionStructure(item, options);
  case 'EnumTypeDefinition':
  case 'EnumTypeExtension':
    return this.toEnumDefinitionStructure(item, options);
  case 'UnionTypeDefinition':
  case 'UnionTypeExtension':
    return this.toUnionDefinitionStructure(item, options);
}

if (includeModules?.length) {
  // Filter metadata by modules
  this.generateUnionDefs(
    TypeMetadataStorage.getUnionsMetadataByModules(includeModules),
  );
  this.generateEnumDefs(
    TypeMetadataStorage.getEnumsMetadataByModules(includeModules),
  );
  this.generateInterfaceDefs(
    options,
    TypeMetadataStorage.getInterfacesMetadataByModules(includeModules),
  );
  this.generateObjectTypeDefs(
    options,
    TypeMetadataStorage.getObjectTypesMetadataByModules(includeModules),
  );
  this.generateInputTypeDefs(
    options,
    TypeMetadataStorage.getInputTypesMetadataByModules(includeModules),
  );
} else {
  // Use all metadata when no module filter is specified
  this.generateUnionDefs();
  this.generateEnumDefs();
  this.generateInterfaceDefs(options);
  this.generateObjectTypeDefs(options);
  this.generateInputTypeDefs(options);
}

export class MiddlewareResolver {
  constructor(
    private readonly middlewareContainer: MiddlewareContainer,
    private readonly injector: Injector,
  ) {}

  public async resolveInstances(moduleRef: Module, moduleName: string) {
    const middlewareMap =
      this.middlewareContainer.getMiddlewareCollection(moduleName);
    const resolveInstance = async (wrapper: InstanceWrapper) =>
      this.resolveMiddlewareInstance(wrapper, middlewareMap, moduleRef);
    await Promise.all([...middlewareMap.values()].map(resolveInstance));
  }

  private async resolveMiddlewareInstance(
    wrapper: InstanceWrapper,
    middlewareMap: Map<InjectionToken, InstanceWrapper>,
    moduleRef: Module,
  ) {
    await this.injector.loadMiddleware(wrapper, middlewareMap, moduleRef);
  }
}

if (
  previousAssignment[assignee] &&
  !isUndefined(previousAssignment[assignee][topic])
) {
  // take the minimum partition since replies will be sent to the minimum partition
  const firstPartition = previousAssignment[assignee][topic];

  // create the assignment with the first partition
  assignment[assignee][topic].push(firstPartition);

  // find and remove this topic and partition from the topicPartitions to be assigned later
  const topicsPartitionsIndex = topicsPartitions.findIndex(
    topicPartition => {
      return (
        topicPartition.topic === topic &&
        topicPartition.partitionId === firstPartition
      );
    },
  );

  // only continue if we found a partition matching this topic
  if (topicsPartitionsIndex !== -1) {
    // remove inline
    topicsPartitions.splice(topicsPartitionsIndex, 1);
  }
}

if (!hasRemarksKey && tags.remarks) {
  // When the @remarks tag is used in the comment, it will be added to the description property of the @ApiOperation decorator.
  // In this case, even when the "controllerKeyOfComment" option is set to "description", the "summary" property will be used.
  const remarksPropertyAssignment = factory.createPropertyAssignment(
    'description',
    createLiteralFromAnyValue(factory, tags.remarks)
  );
  properties.push(remarksPropertyAssignment);

  if (options.controllerKeyOfComment === 'description') {
    unshiftIfNotExisting('summary', extractedComments);
  } else {
    unshiftIfNotExisting(options.controllerKeyOfComment, extractedComments);
  }
} else {
  // No @remarks tag was found in the comment so use the attribute set by the user
  unshiftIfNotExisting(options.controllerKeyOfComment, extractedComments);
}

if (isRelation) {
    // Find the relation by path and get the target entity metadata
    const relationPath = columnProperties.column.split('.')
    // The base entity is the starting point
    let currentMetadata = metadata

    // Traverse the relation path to find the target metadata
    for (let i = 0; i < relationPath.length - 1; i++) {
        const relationName = relationPath[i]
        const relation = currentMetadata.findRelationWithPropertyPath(relationName)

        if (relation) {
            // Update the metadata to the target entity metadata for the next iteration
            currentMetadata = relation.inverseEntityMetadata
        } else {
            break
        }
    }

    // Now get the property from the target entity
    const propertyName = relationPath[relationPath.length - 1]
    columnMeta = currentMetadata.columns.find((col) => col.propertyName === propertyName)
}

if (OpenApiTypeChecker.isTuple(props.schema))
        return writeTuple({
          components: props.components,
          importer: props.importer,
          schema: props.schema,
        });
      else if (OpenApiTypeChecker.isObject(props.schema))
        return writeObject({
          components: props.components,
          importer: props.importer,
          schema: props.schema,
        });
      else if (OpenApiTypeChecker.isReference(props.schema))
        return writeReference({
          importer: props.importer,
          schema: props.schema,
        });
      // UNION
      else if (OpenApiTypeChecker.isOneOf(props.schema))
        return writeUnion({
          components: props.components,
          importer: props.importer,
          elements: props.schema.oneOf,
        });
      else if (OpenApiTypeChecker.isNull(props.schema))
        return createNode("null");
      else return TypeFactory.keyword("any");

if (OpenApiTypeChecker.isObject(props.schema))
